// Validate sender and parse Telegram message into a dev-loop task
const msg = $input.first().json;
const message = msg.message || {};
const text = (message.text || '').trim();
const chatId = message.chat?.id;
const senderId = message.from?.id;
const senderName = message.from?.first_name || 'operator';

// Only accept messages from the configured operator chat
// Hardcoded — n8n Cloud blocks $env access in Code nodes
const allowedChatId = '8747048300';
if (String(chatId) !== allowedChatId) {
  return [{ json: { rejected: true, reason: 'unauthorized_chat', chatId } }];
}

// Ignore empty messages and commands that aren't tasks
if (!text || text.startsWith('/start') || text.startsWith('/help')) {
  return [{ json: {
    rejected: true,
    reason: text ? 'command' : 'empty',
    chatId,
    help_response: 'Send a plain text message describing a task. Example:\n\nAdd a formatPhoneNumber utility in packages/shared/src/ that normalizes US numbers to E.164'
  } }];
}

// Strip /task prefix if present
let taskText = text;
if (taskText.startsWith('/task ')) {
  taskText = taskText.substring(6).trim();
}

// Generate deterministic task_id from timestamp + short hash
const ts = Date.now();
const shortHash = ts.toString(36).slice(-6);
const taskId = `tg-${shortHash}`;

// Extract title: first line or first 60 chars
const firstLine = taskText.split('\n')[0];
const title = firstLine.length > 60 ? firstLine.substring(0, 57) + '...' : firstLine;

// Build TaskContract
const task = {
  task_id: taskId,
  title: title,
  goal: taskText,
  scope_boundaries: [],
  files_allowed: ['apps/api/**', 'packages/shared/**'],
  files_forbidden: [
    '**/auth/**', '**/billing/**', '**/stripe/**',
    '**/twilio/**', '**/oauth/**', '**/provisioning/**',
    '**/deploy/**', '**/migration/**'
  ],
  critical_systems_risk: false,
  expected_output: [],
  checks_required: ['typecheck']
};

return [{ json: {
  rejected: false,
  task,
  chatId,
  senderName,
  messageId: message.message_id
} }];

// Three-way classifier: SIMPLE (help) / OPERATOR (system commands) / COMPLEX (task)
const parsed = $input.first().json;
if (parsed.rejected) return [{ json: parsed }];

const text = (parsed.task.goal || '').toLowerCase().trim();

// SIMPLE: help/guidance patterns
const SIMPLE_WHITELIST = [
  /^\/?help$/,
  /^\/?start$/,
  /^(hi|hello|hey)$/,
  /^what (can|do) (i|you)/,
  /^how (do|should|can) i (send|write|format|submit|use)/,
  /^(give|show|send) (me )?(an? )?example/,
  /^example/,
  /^what (is|does) (simple|complex|this|the bot)/,
  /^what (kind|type)s? of (task|message|request|command)/,
  /^how does this (work|bot)/,
  /^what (commands|options|formats?)/,
  /^(commands|options|usage|guide|instructions)/,
];

// OPERATOR: system control / status / task management commands
const OPERATOR_PATTERNS = [
  // English
  /^(next|find next|start next|get next)\s*(task|job|work)?\s*$/,
  /^continue/,
  /^(resume|proceed|go|carry on)/,
  /^(status|state|what.?s (running|pending|happening|going on|next|the (status|state)))/,
  /^(list|show|get|what are|check)\s*(tasks?|jobs?|queue|pending|failed|available|open)/,
  /^(pending|failed|blocked|done|review)\s*(tasks?|jobs?|items?)?$/,
  /^what (is|are) (the )?(next|available|pending|open) (task|job|work)/,
  /^(any|are there) (pending|available|open|new) (task|job|work)/,
  /^(task|job)\s*(status|list|count|summary|queue)/,
  /^(summary|overview|dashboard|report)/,
  /^(what should i|what to) (do|work on)/,
  /^what.?s next/,
  // Lithuanian
  /^(sekanti|kita|naujas?)\s*(u[zž]duoti|task|darb)/i,
  /^(prad[eė](k|ti)|start)\s*(sekanci|kit|nauj)/i,
  /^(t[eę]sk?|t[eę]sti|toliau|pirmyn)/i,
  /^(imk?|imti|pa[iy]mk?)\s*(kit|sekanci|nauj)/i,
  /^(rask?|rasti|surask?)\s*(sekanci|kit|nauj)/i,
  /^(b[uū]kl[eė]|statusas|pad[eė]tis)/i,
  /^(kokie?|koks?)\s*(task|u[zž]duot|darb)/i,
  /^kas (toliau|sekantis|kitas)/i,
  /^(eik?|va[zž]iuok?)\s*toliau/i,
];

const isSimple = SIMPLE_WHITELIST.some(p => p.test(text));
const isOperator = !isSimple && OPERATOR_PATTERNS.some(p => p.test(text));

let classification = 'COMPLEX';
if (isSimple) classification = 'SIMPLE';
else if (isOperator) classification = 'OPERATOR';

return [{ json: { ...parsed, classification } }];

// Format task summary for Telegram
const parsed = $('Parse Message into Task').first().json;
const summary = $input.first().json;

// Handle API errors
if (summary.error || summary.statusCode >= 400) {
  return [{ json: {
    chatId: parsed.chatId,
    replyText: 'Could not fetch task summary.\nAPI error: ' + (summary.error || summary.message || 'unknown')
  } }];
}

const counts = summary.counts || {};
const recent = summary.recent || [];
const needsReview = summary.needs_review || [];
const pending = summary.pending || [];
const failed = summary.failed || [];

let msg = '📋 Task Queue Summary\n\n';

// Counts
msg += `Total: ${counts.total || 0}  |  `;
msg += `Done: ${counts.done || 0}  |  `;
msg += `Pending: ${counts.pending || 0}  |  `;
msg += `Failed: ${counts.failed || 0}  |  `;
msg += `Blocked: ${counts.blocked || 0}\n`;
msg += `Needs review: ${counts.needs_review || 0}  |  `;
msg += `Stale: ${counts.stale || 0}\n\n`;

// Needs review
if (needsReview.length > 0) {
  msg += '⏳ Needs Review:\n';
  needsReview.forEach(t => {
    msg += `  • ${t.task_id}: ${t.title} [${t.status}]`;
    if (t.branch) msg += ` → ${t.branch}`;
    msg += '\n';
  });
  msg += '\n';
}

// Pending
if (pending.length > 0) {
  msg += '🔜 Pending:\n';
  pending.forEach(t => {
    msg += `  • ${t.task_id}: ${t.title}\n`;
  });
  msg += '\n';
}

// Failed
if (failed.length > 0) {
  msg += '❌ Failed:\n';
  failed.forEach(t => {
    msg += `  • ${t.task_id}: ${t.title}\n`;
  });
  msg += '\n';
}

// Recent
if (recent.length > 0) {
  msg += '📝 Recent:\n';
  recent.forEach(t => {
    msg += `  • ${t.task_id}: ${t.title} [${t.status}]\n`;
  });
  msg += '\n';
}

// No tasks at all
if ((counts.total || 0) === 0) {
  msg += 'No tasks in queue.\n\nSend a task description to create one.';
}

// Next action guidance
if (counts.pending > 0 || counts.needs_review > 0) {
  msg += 'To start a specific task, describe what to do (e.g. "fix the booking date parser").';
} else if (counts.total > 0 && counts.pending === 0) {
  msg += 'No pending tasks. Send a new task description to create one.';
}

return [{ json: { chatId: parsed.chatId, replyText: msg } }];

const parsed = $('Parse Message into Task').first().json;
const task = parsed.task;
const title = task.title.length > 80 ? task.title.substring(0, 77) + '...' : task.title;
return [{ json: {
  chatId: parsed.chatId,
  replyText: 'Task received: ' + title + '\nAnalyzing...'
} }];

// Build final result message for Telegram
const parsed = $('Parse Message into Task').first().json;
const task = parsed.task;
const orchestratorResult = $input.first().json;

let status = 'submitted';
let decision = '';
if (orchestratorResult.review_packet) {
  const rp = orchestratorResult.review_packet;
  status = rp.goal_match === 'full' ? 'done' : rp.goal_match || 'processing';
  decision = rp.recommended_decision || '';
} else if (orchestratorResult.action) {
  decision = orchestratorResult.action;
  if (orchestratorResult.action === 'ESCALATE') status = 'escalated';
  else if (orchestratorResult.action === 'RETRY') status = 'retrying';
  else status = 'done';
} else if (orchestratorResult.error || orchestratorResult.statusCode >= 400) {
  status = 'failed (orchestrator error)';
}

let reply = `Task: ${task.task_id}\n`;
reply += `Title: ${task.title}\n`;
reply += `Status: ${status}\n`;
if (decision) reply += `Decision: ${decision}\n`;
if (orchestratorResult.review_packet?.branch) {
  reply += `Branch: ${orchestratorResult.review_packet.branch}\n`;
}

return [{ json: {
  chatId: parsed.chatId,
  replyText: reply
} }];

// Handle rejected messages (unauthorized chat, empty, /help)
const data = $input.first().json;

if (data.reason === 'command' || data.reason === 'empty') {
  return [{ json: {
    chatId: data.chatId,
    replyText: data.help_response || 'Send a plain text message describing a task.'
  } }];
}

// Unauthorized chat — do not respond (silent reject)
return [];
